import{_ as n,o as s,c as l,j as a,a as t}from"./chunks/framework.CVjg771q.js";const f=JSON.parse('{"title":"生肖 · 鸡","description":"酉鸡——守信准时，金鸡报晓","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 鸡","description":"酉鸡——守信准时，金鸡报晓"},"headers":[],"relativePath":"changshi/shengxiao/ji.md","filePath":"changshi/shengxiao/ji.md","lastUpdated":1779783531000}'),i={name:"changshi/shengxiao/ji.md"};function r(o,e,c,d,h,p){return s(),l("div",null,[...e[0]||(e[0]=[a("h1",{id:"酉鸡",tabindex:"-1"},[t("酉鸡 "),a("a",{class:"header-anchor",href:"#酉鸡","aria-label":'Permalink to "酉鸡"'},"​")],-1),a("blockquote",null,[a("p",null,"地支「酉」· 酉时（17:00–19:00）· 五行属金 · 阴阳为阴")],-1),a("p",null,"鸡守信准时，尽职尽责。酉时鸡开始进笼归窝、夜宿。古代没有先进准确的计时工具，百姓起床劳作主要依靠公鸡打鸣报时。无论严寒酷暑、风霜雨雪，鸡都敬业守时、从不偷懒。鸡还勤奋，整天四处觅食，繁殖能力强、成活率高。",-1),a("h2",{id:"生肖故事-金嗓子换来的生肖",tabindex:"-1"},[t("生肖故事：金嗓子换来的生肖 "),a("a",{class:"header-anchor",href:"#生肖故事-金嗓子换来的生肖","aria-label":'Permalink to "生肖故事：金嗓子换来的生肖"'},"​")],-1),a("p",null,"玉帝选生肖时，鸡也跃跃欲试。但它听说玉帝依据动物们对人类的贡献来挑选，眼看着其他动物一个接一个地入选了，鸡心里非常着急。它跑去问马：「马大哥，怎样才能入选生肖呢？」马答道：「要想封生肖，还得看你对人类有无功劳。你看我帮人们运送货物，打仗时冲锋陷阵；牛帮农民耕田犁地；狗帮人看门……我们都对人类有所贡献，玉帝才准许我们入选。」",-1),a("p",null,"鸡左思右想自己如何能帮助人类。它突然想到自己天生有一副金嗓子——可以每天早上司晨报晓，告诉人们天亮了！这样人们就可以听着自己的鸣叫起床，然后下地干活儿了。",-1),a("p",null,"一天晚上，鸡梦到自己向玉帝哭诉：「我每天守夜报晓，没有功劳也有苦劳，为何不能入选生肖呢？」玉帝听了觉得很有道理，顺手摘下殿前一朵红花戴在鸡的头上。等到第二天醒来，鸡发现自己头上多了一朵红花——玉帝已经将自己选入了生肖。直到今日，鸡依旧每天拂晓准时打鸣，无论刮风下雨还是严寒酷暑，从来不倦怠。",-1)])])}const m=n(i,[["render",r]]);export{f as __pageData,m as default};
